sn_aia_tool.script:
(function(inputs) {
    var query = inputs.search_query;
    try {
        var request = new sn_search.RAGRetrievalRequest()
            .searchProfile('sn_km_portal_knowledge_portal_search_profile')
            .limit(3)
            .sources([new sn_search.RAGRetrievalSource()
                .sourceTableName('kb_knowledge')
                .fields(['number', 'short_description', 'text'])
                .filter('kb_knowledge_baseIN589b035e1a034b679b491bc527987c75,medtric_warranty_policies_kb^workflow_state=published')])
            .query(query)
            .semanticConfiguration(new sn_search.RAGRetrievalSemanticConfiguration()
                .documentMatchThreshold(0.5)
                .embeddingModelId('E5FT')
                .semanticIndexNames(['body'])
                .mode('DEFAULT'));
        var response = new sn_search.RAGRetrievalAPI().retrieve(request);
        var searchResults = response.getSearchResults();
        if (!searchResults || searchResults.length === 0) {
            return JSON.stringify({
                status: 'no_results',
                articles: [],
                message: 'No warranty policy articles found for: ' + query
            });
        }
        var articles = [];
        for (var i = 0; i < searchResults.length; i++) {
            var result = searchResults[i];
            var columns = result.getColumns();
            articles.push({
                number: columns.number || '',
                title: columns.short_description || '',
                content: columns.text || ''
            });
        }
        return JSON.stringify({
            status: 'success',
            articles: articles,
            message: 'Found ' + articles.length + ' policy article(s) for: ' + query
        });
    } catch (e) {
        return JSON.stringify({
            status: 'error',
            articles: [],
            message: 'Search error: ' + e.message
        });
    }
})(inputs);
